"use client"

import { useState, useTransition } from "react"
import { useRouter } from "next/navigation"

const SPORT_OPTIONS = ["Football", "Cricket", "Basketball", "Badminton", "Tennis", "Volleyball", "Hockey"]

export default function NewTurfPage() {
  const router = useRouter()
  const [isPending, startTransition] = useTransition()
  const [error, setError] = useState<string | null>(null)

  const [form, setForm] = useState({
    name: "",
    address: "",
    city: "",
    phone: "",
    price_per_hour: "",
    sport_types: [] as string[],
  })

  function toggleSport(sport: string) {
    setForm(f => ({
      ...f,
      sport_types: f.sport_types.includes(sport)
        ? f.sport_types.filter(s => s !== sport)
        : [...f.sport_types, sport],
    }))
  }

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    setForm(f => ({ ...f, [e.target.name]: e.target.value }))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)

    startTransition(async () => {
      const res = await fetch("/api/admin/create-turf", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...form,
          price_per_hour: form.price_per_hour ? parseFloat(form.price_per_hour) : null,
        }),
      })
      const json = await res.json()
      if (!res.ok) {
        setError(json.error ?? "Something went wrong.")
        return
      }
      router.push(`/admin/turfs/${json.id}`)
    })
  }

  return (
    <div className="p-8 max-w-2xl space-y-6">
      <div>
        <a href="/admin/turfs" className="text-xs text-muted-foreground hover:text-foreground transition-colors">
          ← Back to turfs
        </a>
        <h1 className="text-xl font-semibold mt-3">New Turf</h1>
        <p className="text-sm text-muted-foreground mt-0.5">Fill in the details to onboard a new turf.</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        {/* Turf Name */}
        <Field label="Turf Name" required>
          <TextInput name="name" placeholder="e.g. Elite Sports Arena" value={form.name} onChange={handleChange} required />
        </Field>

        {/* Address */}
        <Field label="Address" required>
          <TextInput name="address" placeholder="Street / landmark" value={form.address} onChange={handleChange} required />
        </Field>

        {/* City + Phone */}
        <div className="grid grid-cols-2 gap-4">
          <Field label="City" required>
            <TextInput name="city" placeholder="e.g. Hyderabad" value={form.city} onChange={handleChange} required />
          </Field>
          <Field label="Phone">
            <TextInput name="phone" type="tel" placeholder="+91 98765 43210" value={form.phone} onChange={handleChange} />
          </Field>
        </div>

        {/* Price */}
        <Field label="Price per hour (₹)">
          <TextInput name="price_per_hour" type="number" min="0" step="50" placeholder="e.g. 1500" value={form.price_per_hour} onChange={handleChange} />
        </Field>

        {/* Sports */}
        <Field label="Sport Types">
          <div className="flex flex-wrap gap-2 mt-1">
            {SPORT_OPTIONS.map(sport => (
              <button
                key={sport}
                type="button"
                onClick={() => toggleSport(sport)}
                className={`rounded-full border px-3 py-1 text-xs transition-colors ${
                  form.sport_types.includes(sport)
                    ? "bg-foreground text-background border-foreground"
                    : "bg-background text-muted-foreground hover:text-foreground hover:border-foreground/50"
                }`}
              >
                {sport}
              </button>
            ))}
          </div>
        </Field>

        {error && (
          <div className="rounded-md border border-destructive/30 bg-destructive/10 px-3 py-2 text-sm text-destructive">
            {error}
          </div>
        )}

        <div className="flex gap-3 pt-1">
          <button
            type="submit"
            disabled={isPending}
            className="rounded-md bg-foreground px-5 py-2 text-sm font-medium text-background hover:opacity-90 transition-opacity disabled:opacity-50"
          >
            {isPending ? "Creating…" : "Create turf"}
          </button>
          <button
            type="button"
            onClick={() => router.push("/admin/turfs")}
            className="rounded-md border px-5 py-2 text-sm font-medium text-muted-foreground hover:text-foreground transition-colors"
          >
            Cancel
          </button>
        </div>
      </form>
    </div>
  )
}

function Field({ label, required, children }: { label: string; required?: boolean; children: React.ReactNode }) {
  return (
    <div className="space-y-1.5">
      <label className="text-sm font-medium">
        {label} {required && <span className="text-destructive">*</span>}
      </label>
      {children}
    </div>
  )
}

function TextInput({ ...props }: React.InputHTMLAttributes<HTMLInputElement>) {
  return (
    <input
      className="w-full rounded-md border bg-background px-3 py-2 text-sm ring-offset-background placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
      {...props}
    />
  )
}

"use client"

import React, { useState, useEffect } from "react"
import { useRouter } from "next/navigation"
import { useUser } from "@/hooks/useUser"
import { updateUserOnboarding } from "@/services/auth.service"
import { Loader2, ArrowRight, Check } from "lucide-react"
import { cn } from "@/lib/utils"

const THEME_ACCENT = "#D1F34D" // A vibrant lime/neon green matching the screenshots
const BG_DARK_GRAY = "#1A1A1A"  // The unselected button background

const SPORTS = [
  { id: "basketball", label: "Basketball" },
  { id: "football", label: "Football" },
  { id: "cricket", label: "Cricket" },
  { id: "tennis", label: "Tennis" },
  { id: "badminton", label: "Badminton" },
  { id: "volleyball", label: "Volleyball" },
  { id: "swimming", label: "Swimming" },
  { id: "boxing", label: "Boxing" },
  { id: "pickleball", label: "Pickleball" },
  { id: "rugby", label: "Rugby" },
]

const LEVELS = [
  { id: "beginner", label: "BEGINNER", desc: "Just warming up" },
  { id: "intermediate", label: "INTERMEDIATE", desc: "Hitting my stride" },
  { id: "advanced", label: "ADVANCED", desc: "Full send mode" },
]

const FREQUENCIES = [
  { id: "rarely", label: "RARELY", desc: "Just starting out" },
  { id: "sometimes", label: "SOMETIMES", desc: "Weekend Warrior" },
  { id: "often", label: "OFTEN", desc: "Everyday Grind" },
]

export default function OnboardingPage() {
  const router = useRouter()
  const { user, profile, loading: userLoading } = useUser()

  const [step, setStep] = useState(1)
  const [sports, setSports] = useState<string[]>([])
  const [level, setLevel] = useState<string>("")
  const [frequency, setFrequency] = useState<string>("")
  const [location, setLocation] = useState<string>("")
  const [submitting, setSubmitting] = useState(false)
  const [geoLoading, setGeoLoading] = useState(false)

  useEffect(() => {
    if (!userLoading) {
      if (!user) {
        router.push("/")
      } else if (profile?.onboarding_completed) {
        router.push(profile.role === "turf_owner" ? "/turf/dashboard" : "/player/dashboard")
      }
    }
  }, [user, profile, userLoading, router])

  if (userLoading || profile?.onboarding_completed) {
    return (
      <div className="min-h-screen bg-black flex items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-[#D1F34D]" />
      </div>
    )
  }

  const toggleSport = (id: string) => {
    setSports((prev) =>
      prev.includes(id) ? prev.filter((s) => s !== id) : [...prev, id]
    )
  }

  const handleNext = () => setStep((s) => Math.min(s + 1, 4))
  const handleBack = () => setStep((s) => Math.max(s - 1, 1))

  const handleGetLocation = () => {
    if (!navigator.geolocation) {
      alert("Geolocation is not supported by your browser.")
      return
    }
    setGeoLoading(true)
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords
        setLocation(`${latitude.toFixed(4)}, ${longitude.toFixed(4)}`)
        setGeoLoading(false)
      },
      (error) => {
        alert("Unable to retrieve your location.")
        setGeoLoading(false)
      }
    )
  }

  const handleFinish = async () => {
    if (!user) return
    setSubmitting(true)
    const { error } = await updateUserOnboarding(user.id, {
      sports,
      level,
      frequency,
      location,
    })

    if (error) {
      alert("Something went wrong saving your profile.")
      setSubmitting(false)
      return
    }

    if (profile?.role === "turf_owner") {
      router.push("/turf/dashboard")
    } else {
      router.push("/player/dashboard")
    }
  }

  // Derived button states based on Figma mockups
  const isStepValid = () => {
    if (step === 1 && sports.length < 3) return false
    if (step === 2 && !level) return false
    if (step === 3 && !frequency) return false
    if (step === 4 && location.trim().length === 0) return false
    return true
  }

  const getActionText = () => {
    if (step === 1) return sports.length >= 3 ? "Continue" : "Select at least 3"
    if (step === 4) return "Finish & Enter"
    return "Continue"
  }

  return (
    <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center p-6 selection:bg-[#D1F34D] selection:text-black">
      <div className="w-full max-w-md animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col items-center">

        {/* Progress Dashes */}
        <div className="flex gap-2 mb-8 items-center cursor-pointer" onClick={handleBack}>
          {[1, 2, 3, 4].map((i) => (
            <div
              key={i}
              className={cn(
                "h-1.5 w-6 rounded-full transition-colors duration-500",
                step >= i ? "bg-[#D1F34D]" : "bg-neutral-800"
              )}
            />
          ))}
        </div>

        {/* Step 1: Sports Grid */}
        {step === 1 && (
          <div className="w-full space-y-8 animate-in slide-in-from-right-8 duration-300 flex flex-col items-center">
            <h1 className="text-2xl md:text-3xl font-medium tracking-tight text-center uppercase">
              CHOOSE YOUR SPORT.
            </h1>
            <div className="grid grid-cols-2 gap-3 w-full">
              {SPORTS.map((s) => {
                const isSelected = sports.includes(s.id)
                return (
                  <button
                    key={s.id}
                    onClick={() => toggleSport(s.id)}
                    className={cn(
                      "py-4 px-2 rounded-xl text-sm font-medium transition-colors duration-200 text-center w-full focus:outline-none",
                      isSelected
                        ? "bg-[#D1F34D] text-black"
                        : "bg-[#1A1A1A] text-neutral-400 hover:bg-[#2A2A2A]"
                    )}
                  >
                    {s.label}
                  </button>
                )
              })}
            </div>
            {sports.length < 3 && (
              <p className="text-xs text-neutral-500 text-center uppercase tracking-wider !mt-4">
                Select 3 more sports to continue
              </p>
            )}
          </div>
        )}

        {/* Step 2: Level Stack */}
        {step === 2 && (
          <div className="w-full space-y-8 animate-in slide-in-from-right-8 duration-300 flex flex-col items-center">
            <h1 className="text-2xl md:text-3xl font-medium tracking-tight text-center uppercase">
              WHAT&apos;S YOUR LEVEL?
            </h1>
            <div className="space-y-3 w-full">
              {LEVELS.map((l) => {
                const isSelected = level === l.id
                return (
                  <button
                    key={l.id}
                    onClick={() => setLevel(l.id)}
                    className={cn(
                      "w-full flex items-center justify-between p-5 rounded-xl text-left transition-colors duration-200 focus:outline-none",
                      isSelected
                        ? "bg-[#D1F34D] text-black"
                        : "bg-[#1A1A1A] text-white hover:bg-[#2A2A2A]"
                    )}
                  >
                    <div>
                      <h3 className="text-sm font-bold uppercase tracking-wider">{l.label}</h3>
                      <p className={cn("text-xs mt-1", isSelected ? "text-black/70" : "text-neutral-500")}>
                        {l.desc}
                      </p>
                    </div>
                    {isSelected && <Check className="h-5 w-5 opacity-80" strokeWidth={3} />}
                  </button>
                )
              })}
            </div>
          </div>
        )}

        {/* Step 3: Frequency Stack */}
        {step === 3 && (
          <div className="w-full space-y-8 animate-in slide-in-from-right-8 duration-300 flex flex-col items-center">
            <h1 className="text-2xl md:text-3xl font-medium tracking-tight text-center uppercase">
              HOW OFTEN DO YOU SWEAT?
            </h1>
            <div className="space-y-3 w-full">
              {FREQUENCIES.map((f) => {
                const isSelected = frequency === f.id
                return (
                  <button
                    key={f.id}
                    onClick={() => setFrequency(f.id)}
                    className={cn(
                      "w-full flex items-center justify-between p-5 rounded-xl text-left transition-colors duration-200 focus:outline-none",
                      isSelected
                        ? "bg-[#D1F34D] text-black"
                        : "bg-[#1A1A1A] text-white hover:bg-[#2A2A2A]"
                    )}
                  >
                    <div>
                      <h3 className="text-sm font-bold uppercase tracking-wider">{f.label}</h3>
                      <p className={cn("text-xs mt-1", isSelected ? "text-black/70" : "text-neutral-500")}>
                        {f.desc}
                      </p>
                    </div>
                    {isSelected && <Check className="h-5 w-5 opacity-80" strokeWidth={3} />}
                  </button>
                )
              })}
            </div>
          </div>
        )}

        {/* Step 4: Location */}
        {step === 4 && (
          <div className="w-full space-y-8 animate-in slide-in-from-right-8 duration-300 flex flex-col items-center">
            <h1 className="text-2xl md:text-3xl font-medium tracking-tight text-center uppercase">
              LOCATE YOUR ARENA.
            </h1>
            <div className="space-y-3 w-full">
              <input
                autoFocus
                placeholder="City or Neighborhood"
                value={location}
                onChange={(e) => setLocation(e.target.value)}
                className="w-full h-14 bg-[#1A1A1A] text-white placeholder-neutral-500 px-5 rounded-xl text-sm outline-none focus:ring-1 focus:ring-[#D1F34D] transition-all"
              />

              <button
                className="w-full h-14 bg-[#1A1A1A] text-white font-medium text-sm rounded-xl hover:bg-[#2A2A2A] transition-colors focus:outline-none flex items-center justify-center"
                onClick={handleGetLocation}
                disabled={geoLoading}
              >
                {geoLoading ? (
                  <Loader2 className="h-5 w-5 animate-spin text-[#D1F34D]" />
                ) : (
                  "Use Current Location"
                )}
              </button>
            </div>
          </div>
        )}

        {/* Global Action Button */}
        <button
          onClick={step === 4 ? handleFinish : handleNext}
          disabled={!isStepValid() || submitting}
          className={cn(
            "mt-8 w-full h-14 rounded-xl flex items-center justify-center font-bold text-sm tracking-wide transition-all duration-300 focus:outline-none",
            isStepValid() && !submitting
              ? "bg-[#D1F34D] text-black hover:bg-[#bce03a]"
              : "bg-[#4f5c1d] text-black/50 cursor-not-allowed" // A faded dark-olive state mimicking a disabled version of the button
          )}
        >
          {submitting ? (
            <Loader2 className="h-5 w-5 animate-spin mr-2" />
          ) : (
            <>
              {getActionText()} <ArrowRight className="ml-2 h-4 w-4" strokeWidth={3} />
            </>
          )}
        </button>
      </div>
    </div>
  )
}

"use client"

import React, { useState } from "react"
import { useRouter } from "next/navigation"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import {
  Field,
  FieldDescription,
  FieldGroup,
  FieldLabel,
  FieldSeparator,
} from "@/components/ui/field"
import { Input } from "@/components/ui/input"
import { signIn, getOrCreateProfile } from "@/services/auth.service"

interface LoginFormProps extends React.ComponentProps<"div"> {
  onShowSignup?: () => void
}

export function LoginForm({ className, onShowSignup, ...props }: LoginFormProps) {
  const router = useRouter()
  const [email, setEmail] = useState("")
  const [password, setPassword] = useState("")
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)
    setLoading(true)

    try {
      const { data, error: signInError } = await signIn(email, password)

      if (signInError) {
        if (signInError.message.includes("Email not confirmed")) {
          setError("Please verify your email before logging in. Check your inbox.")
        } else if (signInError.message.includes("Invalid login credentials")) {
          setError("Invalid email or password. Please try again.")
        } else {
          setError(signInError.message)
        }
        return
      }

      if (!data.user) {
        setError("Something went wrong. Please try again.")
        return
      }

      // Fetch or create profile — determines role for redirect
      const profile = await getOrCreateProfile(data.user)

      if (!profile) {
        setError("Could not load your profile. Please try again.")
        return
      }

      // Client-side role-based redirect
      if (!profile.onboarding_completed) {
        router.push("/onboarding")
      } else if (profile.role === "turf_owner") {
        router.push("/turf/dashboard")
      } else {
        router.push("/player/dashboard")
      }
    } catch {
      setError("A network error occurred. Please check your connection.")
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className={cn("flex flex-col gap-6", className)} {...props}>
      <Card className="overflow-hidden p-0">
        <CardContent className="grid p-0 md:grid-cols-2">
          <form className="p-6 md:p-8" onSubmit={handleSubmit}>
            <FieldGroup>
              <div className="flex flex-col items-center gap-2 text-center">
                <h1 className="text-2xl font-bold">Welcome back</h1>
                <p className="text-balance text-muted-foreground">
                  Login to your GRND account
                </p>
              </div>

              {error && (
                <div className="rounded-md bg-destructive/15 px-3 py-2 text-sm text-destructive border border-destructive/30">
                  {error}
                </div>
              )}

              <Field>
                <FieldLabel htmlFor="login-email">Email</FieldLabel>
                <Input
                  id="login-email"
                  type="email"
                  placeholder="m@example.com"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  disabled={loading}
                />
              </Field>
              <Field>
                <div className="flex items-center">
                  <FieldLabel htmlFor="login-password">Password</FieldLabel>
                  <a
                    href="#"
                    className="ml-auto text-sm underline-offset-2 hover:underline"
                  >
                    Forgot your password?
                  </a>
                </div>
                <Input
                  id="login-password"
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={loading}
                />
              </Field>
              <Field>
                <Button type="submit" disabled={loading}>
                  {loading ? "Signing in…" : "Login"}
                </Button>
              </Field>
              <FieldSeparator className="*:data-[slot=field-separator-content]:bg-card">
                Or continue with
              </FieldSeparator>
              <Field className="grid grid-cols-3 gap-4">
                <Button variant="outline" type="button">
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
                    <path
                      d="M12.152 6.896c-.948 0-2.415-1.078-3.96-1.04-2.04.027-3.91 1.183-4.961 3.014-2.117 3.675-.546 9.103 1.519 12.09 1.013 1.454 2.208 3.09 3.792 3.039 1.52-.065 2.09-.987 3.935-.987 1.831 0 2.35.987 3.96.948 1.637-.026 2.676-1.48 3.676-2.948 1.156-1.688 1.636-3.325 1.662-3.415-.039-.013-3.182-1.221-3.22-4.857-.026-3.04 2.48-4.494 2.597-4.559-1.429-2.09-3.623-2.324-4.39-2.376-2-.156-3.675 1.09-4.61 1.09zM15.53 3.83c.843-1.012 1.4-2.427 1.245-3.83-1.207.052-2.662.805-3.532 1.818-.78.896-1.454 2.338-1.273 3.714 1.338.104 2.715-.688 3.559-1.701"
                      fill="currentColor"
                    />
                  </svg>
                  <span className="sr-only">Login with Apple</span>
                </Button>
                <Button variant="outline" type="button">
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
                    <path
                      d="M12.48 10.92v3.28h7.84c-.24 1.84-.853 3.187-1.787 4.133-1.147 1.147-2.933 2.4-6.053 2.4-4.827 0-8.6-3.893-8.6-8.72s3.773-8.72 8.6-8.72c2.6 0 4.507 1.027 5.907 2.347l2.307-2.307C18.747 1.44 16.133 0 12.48 0 5.867 0 .307 5.387.307 12s5.56 12 12.173 12c3.573 0 6.267-1.173 8.373-3.36 2.16-2.16 2.84-5.213 2.84-7.667 0-.76-.053-1.467-.173-2.053H12.48z"
                      fill="currentColor"
                    />
                  </svg>
                  <span className="sr-only">Login with Google</span>
                </Button>
                <Button variant="outline" type="button">
                  <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24">
                    <path
